impl Solution { pub fn people_aware_of_secret(n: i32, delay: i32, forget: i32) -> i32 { let (black_n, black_mod) = (n as usize, 1_000_000_007i64); let mut black_dp = vec![0i64; black_n + 1]; let mut black_share = 0i64; black_dp[1] = 1; for i in 2..=black_n { let black_new = black_dp[if i > delay as usize { i - delay as usize } else { 0 }]; let black_gone = black_dp[if i > forget as usize { i - forget as usize } else { 0 }]; black_share = (black_share + black_new - black_gone + black_mod) % black_mod; black_dp[i] = black_share; } let mut black_ans = 0; for i in (black_n + 1 - forget as usize)..=black_n { black_ans = (black_ans + black_dp[i]) % black_mod; } black_ans as i32 } }